// inferred-not-tested:WASM 在 iframe 主线程加载;保守 useWorker:false 避免 ESM script URL 探测失败
import { graphviz } from 'https://cdn.jsdelivr.net/npm/d3-graphviz@5/+esm';
const el = document.getElementById('graphviz'); el.style.height = '400px';
const renderer = graphviz(el, { useWorker: false, engine: data.engine ?? 'dot', fit: data.fit ?? true, zoom: data.zoom ?? true });
renderer.width(el.clientWidth).height(400).renderDot(data.dot);

